import Stripe from 'stripe'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

// Record a single usage event
export async function recordUsageEvent(
  customerId: string,
  meterId: string,
  value: number,
  idempotencyKey: string
) {
  try {
    await stripe.billing.meterEvents.create({
      event_name: meterId,
      payload: {
        stripe_customer_id: customerId,
        value: value.toString(),
      },
    }, {
      idempotencyKey: idempotencyKey,
    })
    return { success: true }
  } catch (error) {
    console.error('Failed to record usage:', error)
    return { success: false, error }
  }
}

// Batch usage recording (for high-volume apps)
export async function recordUsageBatch(
  events: Array<{
    customerId: string
    meterId: string
    value: number
    idempotencyKey: string
  }>
) {
  const results = await Promise.allSettled(
    events.map(e => recordUsageEvent(
      e.customerId,
      e.meterId,
      e.value,
      e.idempotencyKey
    ))
  )
  return results
}

// Get current meter usage
export async function getMeterUsage(
  customerId: string,
  meterId: string
): Promise<number> {
  const meterEventSummaries = await stripe.billing.meters.listEventSummaries(
    meterId,
    {
      customer: customerId,
      start_time: Math.floor(Date.now() / 1000) - 30 * 24 * 60 * 60, // Last 30 days
      end_time: Math.floor(Date.now() / 1000),
    }
  )

  return meterEventSummaries.data.reduce(
    (sum, summary) => sum + summary.aggregated_value,
    0
  )
}

subscription-create.code:
import Stripe from 'stripe'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

export async function createSubscription(
  customerId: string,
  priceId: string,
  options?: {
    trialDays?: number
    quantity?: number
    metadata?: Record<string, string>
  }
) {
  const subscriptionParams: Stripe.SubscriptionCreateParams = {
    customer: customerId,
    items: [{ price: priceId, quantity: options?.quantity || 1 }],
    payment_behavior: 'default_incomplete',
    payment_settings: {
      save_default_payment_method: 'on_subscription',
    },
    expand: ['latest_invoice.payment_intent'],
    metadata: options?.metadata,
  }

  if (options?.trialDays) {
    subscriptionParams.trial_period_days = options.trialDays
  }

  const subscription = await stripe.subscriptions.create(subscriptionParams)

  return {
    subscriptionId: subscription.id,
    status: subscription.status,
    clientSecret: (subscription.latest_invoice as Stripe.Invoice)
      ?.payment_intent
      ? ((subscription.latest_invoice as Stripe.Invoice).payment_intent as Stripe.PaymentIntent).client_secret
      : null,
  }
}

