import Stripe from 'stripe'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

// Preview proration before making changes
export async function previewProration(
  subscriptionId: string,
  newPriceId: string
): Promise<{ amount: number; description: string }> {
  const subscription = await stripe.subscriptions.retrieve(subscriptionId)

  const proration_date = Math.floor(Date.now() / 1000)

  const invoice = await stripe.invoices.retrieveUpcoming({
    customer: subscription.customer as string,
    subscription: subscriptionId,
    subscription_items: [{
      id: subscription.items.data[0].id,
      price: newPriceId,
    }],
    subscription_proration_date: proration_date,
  })

  // Find proration line items
  const prorationItems = invoice.lines.data.filter(
    line => line.proration
  )

  const totalProration = prorationItems.reduce(
    (sum, item) => sum + item.amount,
    0
  )

  return {
    amount: totalProration, // In cents
    description: totalProration >= 0 
      ? `You'll be charged $${(totalProration / 100).toFixed(2)} now`
      : `You'll receive a credit of $${(Math.abs(totalProration) / 100).toFixed(2)}`,
  }
}

