import Stripe from 'stripe'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

// Standard trial: Free access, then billing starts
export async function createTrialSubscription(
  customerId: string,
  priceId: string,
  trialDays: number = 14
) {
  const subscription = await stripe.subscriptions.create({
    customer: customerId,
    items: [{ price: priceId }],
    trial_period_days: trialDays,
    payment_behavior: 'default_incomplete',
    payment_settings: {
      save_default_payment_method: 'on_subscription',
    },
    expand: ['latest_invoice.payment_intent'],
  })

  return subscription
}

// Reverse trial: Start on Pro, downgrade to Free after trial
// Implementation pattern:
// 1. Create user on Pro plan with trial
// 2. Listen to customer.subscription.trial_will_end webhook
// 3. If no payment method, downgrade to free tier
// 4. If payment method exists, trial converts to paid

export async function handleTrialEnding(
  subscriptionId: string,
  freePriceId: string
) {
  const subscription = await stripe.subscriptions.retrieve(subscriptionId, {
    expand: ['customer'],
  })

  const customer = subscription.customer as Stripe.Customer

  // Check if customer has payment method
  const paymentMethods = await stripe.paymentMethods.list({
    customer: customer.id,
    type: 'card',
  })

  if (paymentMethods.data.length === 0) {
    // No payment method - downgrade to free
    await stripe.subscriptions.update(subscriptionId, {
      items: [{
        id: subscription.items.data[0].id,
        price: freePriceId,
      }],
      trial_end: 'now', // End trial immediately
    })
    return { action: 'downgraded_to_free' }
  }

  // Has payment method - trial will convert to paid automatically
  return { action: 'converting_to_paid' }
}

dunning-handler.code:
import Stripe from 'stripe'
import { createServiceClient } from '@/lib/supabase/server'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

// Webhook handler for payment failures
export async function handlePaymentFailed(
  invoice: Stripe.Invoice
) {
  const supabase = createServiceClient()
  const subscriptionId = invoice.subscription as string

  // Calculate grace period (7 days from now)
  const gracePeriodUntil = new Date()
  gracePeriodUntil.setDate(gracePeriodUntil.getDate() + 7)

  // Update subscription status
  await supabase
    .from('subscriptions')
    .update({
      status: 'past_due',
      dunning_started_at: new Date().toISOString(),
      grace_period_until: gracePeriodUntil.toISOString(),
      dunning_emails_sent: 1,
    })
    .eq('id', subscriptionId)

  // TODO: Send dunning email #1
  // "Payment failed. Update your card to avoid service interruption."

  return { action: 'dunning_started' }
}

// Webhook handler for payment recovery
export async function handlePaymentRecovered(
  invoice: Stripe.Invoice
) {
  const supabase = createServiceClient()
  const subscriptionId = invoice.subscription as string

  // Clear dunning state
  await supabase
    .from('subscriptions')
    .update({
      status: 'active',
      dunning_started_at: null,
      grace_period_until: null,
      dunning_emails_sent: 0,
    })
    .eq('id', subscriptionId)

  // TODO: Send recovery confirmation email

  return { action: 'payment_recovered' }
}

// Check if user is in grace period (still has access)
export async function checkGracePeriod(
  userId: string
): Promise<{ hasAccess: boolean; daysRemaining: number | null }> {
  const supabase = createServiceClient()

  const { data: subscription } = await supabase
    .from('subscriptions')
    .select('status, grace_period_until')
    .eq('user_id', userId)
    .single()

  if (!subscription) {
    return { hasAccess: false, daysRemaining: null }
  }

  if (subscription.status === 'active') {
    return { hasAccess: true, daysRemaining: null }
  }

  if (subscription.status === 'past_due' && subscription.grace_period_until) {
    const gracePeriodEnd = new Date(subscription.grace_period_until)
    const now = new Date()

    if (now < gracePeriodEnd) {
      const daysRemaining = Math.ceil(
        (gracePeriodEnd.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)
      )
      return { hasAccess: true, daysRemaining }
    }
  }

  return { hasAccess: false, daysRemaining: 0 }
}

