import Stripe from 'stripe'
import { createServiceClient } from '@/lib/supabase/server'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

// Add a seat (team member added)
export async function addSeat(
  subscriptionId: string,
  prorationBehavior: 'always_invoice' | 'create_prorations' = 'always_invoice'
) {
  const subscription = await stripe.subscriptions.retrieve(subscriptionId)
  const currentQuantity = subscription.items.data[0].quantity || 1

  const updatedSubscription = await stripe.subscriptions.update(subscriptionId, {
    items: [{
      id: subscription.items.data[0].id,
      quantity: currentQuantity + 1,
    }],
    proration_behavior: prorationBehavior,
  })

  return {
    newQuantity: currentQuantity + 1,
    subscription: updatedSubscription,
  }
}

// Remove a seat (team member removed)
export async function removeSeat(
  subscriptionId: string,
  prorationBehavior: 'create_prorations' | 'none' = 'create_prorations'
) {
  const subscription = await stripe.subscriptions.retrieve(subscriptionId)
  const currentQuantity = subscription.items.data[0].quantity || 1

  if (currentQuantity <= 1) {
    throw new Error('Cannot reduce below 1 seat')
  }

  const updatedSubscription = await stripe.subscriptions.update(subscriptionId, {
    items: [{
      id: subscription.items.data[0].id,
      quantity: currentQuantity - 1,
    }],
    proration_behavior: prorationBehavior,
  })

  return {
    newQuantity: currentQuantity - 1,
    subscription: updatedSubscription,
  }
}

// Sync seat count from database (nightly job pattern)
export async function syncSeatCount(
  teamId: string,
  subscriptionId: string
) {
  const supabase = createServiceClient()

  // Count active team members
  const { count } = await supabase
    .from('team_members')
    .select('*', { count: 'exact', head: true })
    .eq('team_id', teamId)
    .eq('role', 'member') // Exclude guests/viewers if they're free

  const subscription = await stripe.subscriptions.retrieve(subscriptionId)
  const currentQuantity = subscription.items.data[0].quantity || 1

  if (count && count !== currentQuantity) {
    await stripe.subscriptions.update(subscriptionId, {
      items: [{
        id: subscription.items.data[0].id,
        quantity: count,
      }],
      proration_behavior: 'create_prorations',
    })

    return { synced: true, oldQuantity: currentQuantity, newQuantity: count }
  }

  return { synced: false, quantity: currentQuantity }
}

usage-records.code:
import Stripe from 'stripe'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, {
  apiVersion: '2024-06-20',
})

// Record usage for a subscription item
export async function recordUsage(
  subscriptionItemId: string,
  quantity: number,
  action: 'increment' | 'set' = 'increment',
  idempotencyKey?: string
) {
  const usageRecord = await stripe.subscriptionItems.createUsageRecord(
    subscriptionItemId,
    {
      quantity,
      action,
      timestamp: Math.floor(Date.now() / 1000),
    },
    {
      idempotencyKey,
    }
  )

  return usageRecord
}

// Get usage summary for current period
export async function getUsageSummary(
  subscriptionItemId: string
) {
  const usageRecords = await stripe.subscriptionItems.listUsageRecordSummaries(
    subscriptionItemId,
    { limit: 1 }
  )

  return usageRecords.data[0] || { total_usage: 0 }
}

